use std::io::{self, Write};
use tempfile::NamedTempFile;

struct CacheEntry {
    key_hash: u32,
    data_size: usize,
}

fn process_cache_dump() -> io::Result<()> {
    let mut tmpfile = NamedTempFile::new().map_err(|e| io::Error::new(io::ErrorKind::Other, format!("Failed to create temp file: {}", e)))?;
    let path = tmpfile.path();

    println!("Simulating writing temporary state block to scratchpad at: {}", path.to_string_lossy());

    let entries: Vec<CacheEntry> = vec![
        CacheEntry { key_hash: 0xDEADBEEF, data_size: 64 },
        CacheEntry { key_hash: 0xFEEDFACE, data_size: 128 },
    ];

    for entry in entries {
        writeln!(tmpfile, "KEY_HASH={:#X}, DATA_SIZE={}", entry.key_hash, entry.data_size)?;
    }

    tmpfile.flush()?;

    println!("Successfully wrote cache dump block. File handle will close automatically.");
    Ok(())
}

fn main() {
    match process_cache_dump() {
        Ok(_) => println!("Operation complete successfully."),
        Err(e) => eprintln!("Error during cache dumping: {}", e),
    }
}

use std::io::{self, Write};
use tempfile::NamedTempFile;
use std::path::PathBuf;

fn process_payloads() -> io::Result<()> {
    let mut file = NamedTempFile::new().map_err(|e| io::Error::new(io::ErrorKind::Other, format!("Failed to create temp file: {}", e))).unwrap();
    let path_buf = file.path().to_owned();

    println!("Created temporary cache at: {}", path_buf.display());

    writeln!(&mut file, "Payload_Start: Batch_ID_123n")?;
    writeln!(&mut file, "Key=google.comnValue=A_Record_Set_XYZn")?;
    writeln!(&mut file, "Event_Flag=Validatedn")?;
    writeln!(&mut file, "Payload_Endn")?;

    let contents = std::fs::read_to_string(path_buf.as_path()).map_err(|e| io::Error::new(io::ErrorKind::Other, format!("Read error: {}", e)))?;
    println!("n--- Temporary File Contents ---n{}", contents);

    Ok(())
}

fn main() {
    if let Err(e) = process_payloads() {
        eprintln!("Operation failed: {}", e);
    }
}
